+    #[test]
+    fn roots_with_repeated_zero_root() {
+        // [1, 0, 0] -> x^2, roots: 0, 0
+        let p = UFuncArray::new(vec![3], vec![1.0, 0.0, 0.0], DType::F64).unwrap();
+        let r = p.roots().unwrap();
+        assert_eq!(r.shape(), &[2]);
+        let mut roots = r.values().to_vec();
+        roots.sort_by(|a, b| a.total_cmp(b));
+        assert_eq!(roots, vec![0.0, 0.0]);
+    }
